// ValidateLocationResponseBody runs the validations defined on
// LocationResponseBody
func ValidateLocationResponseBody(body *LocationResponseBody) (err error) {
	if body.Name == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("name", "body"))
	}
	if body.Source == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("source", "body"))
	}
	if body.Purpose == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("purpose", "body"))
	}
	if body.UUID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("uuid", "body"))
	}
	if body.CreatedAt == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("created_at", "body"))
	}
	if body.Source != nil {
		if !(*body.Source == "unspecified" || *body.Source == "minio" || *body.Source == "sftp" || *body.Source == "amss") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.source", *body.Source, []any{"unspecified", "minio", "sftp", "amss"}))
		}
	}
	if body.Purpose != nil {
		if !(*body.Purpose == "unspecified" || *body.Purpose == "aip_store") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.purpose", *body.Purpose, []any{"unspecified", "aip_store"}))
		}
	}
	switch string(body.Config.Kind()) {
	case "amss":
		actual, _ := body.Config.AsAmss()
		if actual != nil {
			if err2 := ValidateAMSSConfigResponseBody(actual); err2 != nil {
				err = goa.MergeErrors(err, err2)
			}
		}
	case "s3":
		actual, _ := body.Config.AsS3()
		if actual != nil {
			if err2 := ValidateS3ConfigResponseBody(actual); err2 != nil {
				err = goa.MergeErrors(err, err2)
			}
		}
	case "sftp":
		actual, _ := body.Config.AsSftp()
		if actual != nil {
			if err2 := ValidateSFTPConfigResponseBody(actual); err2 != nil {
				err = goa.MergeErrors(err, err2)
			}
		}
	case "url":
		actual, _ := body.Config.AsURL()
		if actual != nil {
			if err2 := ValidateURLConfigResponseBody(actual); err2 != nil {
				err = goa.MergeErrors(err, err2)
			}
		}
	}

	if body.CreatedAt != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.created_at", *body.CreatedAt, goa.FormatDateTime))
	}
	return
}

